import React, { useEffect, useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";

export default function AddTravel({ employee }) {
  const [form, setForm] = useState({
    travel_date: "",
    purpose: "",
    amount: "",
    location_from: "",
    location_to: "",
    mode_of_travel: "",
    expense_type: "Transport",
  });

  const [history, setHistory] = useState([]);
  const [message, setMessage] = useState("");
  const [filterMonth, setFilterMonth] = useState("");

  // Load employee travel history
  const loadHistory = async () => {
    try {
      const res = await fetch(`${apiBase}/travel-expenses`);
      const data = await res.json();

      setHistory(
        data.filter((t) => t.employee_id === employee.employee_id)
      );
    } catch (err) {
      console.error("History error:", err);
      setMessage("❌ Could not load travel history");
    }
  };

  useEffect(() => {
    loadHistory();
  }, []);

  // Submit Travel Expense
  const submitTravel = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch(`${apiBase}/travel-expenses`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          employee_id: employee.employee_id,
          ...form,
          amount: parseFloat(form.amount),
        }),
      });

      const data = await res.json();
      if (data.success) {
        setMessage("✅ Travel Expense Added");
        loadHistory();
        setForm({
          travel_date: "",
          purpose: "",
          amount: "",
          location_from: "",
          location_to: "",
          mode_of_travel: "",
          expense_type: "Transport",
        });
      } else {
        setMessage("❌ " + data.message);
      }
    } catch (error) {
      console.error(error);
      setMessage("❌ Error submitting expense");
    }
  };

  // Delete Expense
  const deleteExpense = async (id) => {
    if (!window.confirm("Delete this record?")) return;

    try {
      const res = await fetch(`${apiBase}/travel-expenses/${id}`, {
        method: "DELETE",
      });

      const data = await res.json();

      if (data.success) {
        setMessage("🗑 Deleted successfully");
        loadHistory();
      }
    } catch (err) {
      console.log(err);
    }
  };

  // Filter by month
  const filteredHistory =
    filterMonth === ""
      ? history
      : history.filter((item) => item.travel_date.startsWith(filterMonth));

  return (
    <div style={{ padding: 20 }}>
      <h1 style={{ color: "#0f9d58" }}>➕ Add Travel Expense</h1>

      {/* Travel Form */}
      <form
        onSubmit={submitTravel}
        style={{
          background: "#ffffff",
          padding: 20,
          borderRadius: 10,
          boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
          maxWidth: 500,
        }}
      >
        <input
          type="date"
          required
          value={form.travel_date}
          onChange={(e) => setForm({ ...form, travel_date: e.target.value })}
          style={inputStyle()}
        />

        <input
          type="text"
          placeholder="Purpose"
          required
          value={form.purpose}
          onChange={(e) => setForm({ ...form, purpose: e.target.value })}
          style={inputStyle()}
        />

        <input
          type="number"
          placeholder="Amount"
          required
          value={form.amount}
          onChange={(e) => setForm({ ...form, amount: e.target.value })}
          style={inputStyle()}
        />

        <input
          type="text"
          placeholder="From Location"
          value={form.location_from}
          onChange={(e) =>
            setForm({ ...form, location_from: e.target.value })
          }
          style={inputStyle()}
        />

        <input
          type="text"
          placeholder="To Location"
          value={form.location_to}
          onChange={(e) =>
            setForm({ ...form, location_to: e.target.value })
          }
          style={inputStyle()}
        />

        <button type="submit" style={buttonPrimary()}>
          Submit
        </button>
      </form>

      {message && <p style={{ color: "#0f9d58", marginTop: 10 }}>{message}</p>}

      {/* Filter */}
      <h2 style={{ marginTop: 30 }}>📅 Travel Expense History</h2>

      <input
        type="month"
        value={filterMonth}
        onChange={(e) => setFilterMonth(e.target.value)}
        style={{ marginBottom: 15, padding: 8 }}
      />

      {/* History Table */}
      <table style={tableStyle()}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>Amount</th>
            <th>Status</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {filteredHistory.map((item) => (
            <tr key={item.travel_id}>
              <td>{item.travel_date}</td>
              <td>{item.purpose}</td>
              <td>₹{item.amount}</td>
              <td>{item.approval_status}</td>

              <td>
                <button
                  onClick={() => deleteExpense(item.travel_id)}
                  style={deleteBtn()}
                >
                  🗑
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* Styles */
const inputStyle = () => ({
  width: "100%",
  padding: 10,
  marginBottom: 10,
  borderRadius: 6,
  border: "1px solid #ccc",
});

const buttonPrimary = () => ({
  padding: "10px 20px",
  background: "#0f9d58",
  border: "none",
  color: "white",
  borderRadius: 6,
  cursor: "pointer",
});

const deleteBtn = () => ({
  background: "red",
  color: "white",
  border: "none",
  padding: "5px 10px",
  borderRadius: 6,
  cursor: "pointer",
});

const tableStyle = () => ({
  width: "100%",
  marginTop: 20,
  borderCollapse: "collapse",
});
